1	const fs = require('fs');
2	const path = require('path');
3	
4	const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
5	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
6	const NOW = Date.now();
7	const DAY = 86400000;
8	const OUR_UID = '2500000853693@icbu';
9	
10	// ── 工具函数 ──
11	const SYS_PATTERNS = [
12	  '自动接待将不再触发', 'Since you have read the conversation',
13	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
14	  '买家有流失风险', 'Buyer has churn risk',
15	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
16	  '反馈', 'AI给您生成了一条回复建议',
17	  'You have a visitor', 'This buyer has been pre-screened',
18	  '当前买家首次给您发消息', 'AI给您生成',
19	];
20	function isSys(c) { const t = c && c.text && c.text.content || ''; if (!t.trim()) return true; for (const p of SYS_PATTERNS) if (t.includes(p)) return true; return false; }
21	function getText(c) { return c && c.text && c.text.content || ''; }
22	
23	const Q_PATTERNS = [/\?/, /(what|how|when|where|which|who|why|whom)/i, /(can you|could you|would you|will you|do you|is it|are you)/i, /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know))/i, /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i, /[吗呢吧啊]/, /[？]/, /(价格|报价|多少钱|什么价)/, /(样品|sample|打样)/i, /(MOQ|起订量|最小.*量)/i, /(交期|delivery.*time|lead.*time)/i];
24	function isQuestion(text) { if (!text || text.length < 3) return false; for (const p of Q_PATTERNS) if (p.test(text)) return true; return false; }
25	
26	function assessQuality(qText, rText) {
27	  if (!rText || rText.trim().length === 0) return { q: '未回复', s: 0 };
28	  const len = rText.trim().length;
29	  if (/^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i.test(rText.trim()) || len < 15) return { q: '敷衍回复', s: 1 };
30	  if (len < 50) return { q: '简短回复', s: 2 };
31	  const qw = (qText || '').toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
32	  const rl = rText.toLowerCase();
33	  const m = qw.filter(w => rl.includes(w));
34	  return (m.length / Math.max(qw.length, 1) >= 0.3 || len >= 100) ? { q: '充分回复', s: 3 } : { q: '简短回复', s: 2 };
35	}
36	
37	// ── 生命周期判定 ──
38	function determineLifecycle(e) {
39	  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
40	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
41	
42	  // 售后：质量问题/投诉
43	  if (/(problem|issue|damage|broken|wrong|defect|complain|refund|return|bad quality|poor quality|not good|有问题|坏的|退货|退款|投诉)/i.test(fullText)) return { stage: 8, label: '售后', icon: '🔧' };
44	
45	  // 订单执行中：付款确认+生产/发货讨论
46	  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };
47	
48	  // 已签收
49	  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };
50	
51	  // PI已发（不限天数，只看信号）
52	  if (hasPI) return { stage: 5, label: 'PI已发', icon: '📄' };
53	
54	  // 谈判/样品（不限天数）
55	  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10) return { stage: 4, label: '谈判/样品', icon: '🤝' };
56	  if (hasSample && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };
57	
58	  // 报价已发（不限天数）
59	  if (hasPrice) return { stage: 3, label: '报价已发', icon: '💰' };
60	
61	  // 待回复：客户有新消息未回
62	  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };
63	
64	  // 初询沟通（不限天数）
65	  if (realMsgs >= 1) return { stage: 2, label: '初询沟通', icon: '📋' };
66	
67	  return { stage: 0, label: '待分类', icon: '❓' };
68	}
69	
70	// ── 沉默副状态 ──
71	function silenceLabel(days) {
72	  if (days >= 90) return '沉淀(90d+)';
73	  if (days >= 30) return '深度沉默(30-90d)';
74	  if (days >= 14) return '长期沉默(14-30d)';
75	  if (days >= 7) return '中期沉默(7-14d)';
76	  if (days >= 3) return '短期沉默(3-7d)';
77	  return '';
78	}
79	
80	// ── 质量等级判定 ──
81	function determineQuality(e) {
82	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '') + ' ' + (e.latestOurMsg || '')).toLowerCase();
83	
84	  // S 级信号
85	  const sSignals = [];
86	  if (/(brand|odm|oem|logo|label|custom.*packag|hangtag|barcode|private.*label|own.*design)/i.test(fullText)) sSignals.push('品牌/ODM/定制包装');
87	  if (/(amazon|walmart|shopify|retail.*chain|distributor.*network|wholesale.*channel)/i.test(fullText)) sSignals.push('分销渠道');
88	  if (/(\d{4,}\s*(pcs|pieces|units|件)|\b[5-9]\d{2,3}\s*(pcs|pieces|units))/i.test(fullText)) sSignals.push('大批量');
89	  if (/(website|store|shop|company.*name|business.*card)/i.test(fullText)) sSignals.push('公司资料');
90	
91	  // C/D 信号
92	  const cSignals = [];
93	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift)/i.test(fullText)) cSignals.push('个人自用');
94	  if (/(\b[1-2]?\d\s*(pcs|pieces|units|件)\b|just.*few|small.*quantity|少量)/i.test(fullText)) cSignals.push('极小量');
95	
96	  // D 信号
97	  if (e.realMsgs <= 2 && e.customerMsgs === 0) return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
98	  if (/(adult|成人|men.*wear|not.*baby|not.*kid)/i.test(fullText) && !(/baby|kid|child|infant/i.test(fullText))) return { grade: 'D', label: '无关', reason: '品类不匹配', auto: true };
99	
100	  if (sSignals.length >= 2) return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
101	  if (sSignals.length >= 1) return { grade: 'A', label: '优质客户', reason: sSignals.join('+') + '(信号待验证)', auto: true };
102	  if (cSignals.length >= 2) return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };
103	
104	  // 有实质对话但信息不足 → B
105	  if (e.realMsgs >= 5 && e.customerMsgs >= 2) return { grade: 'B', label: '普通客户', reason: '信息不足自动定B', auto: true };
106	  if (e.hasPrice || e.hasSample || e.hasQuantity) return { grade: 'B', label: '普通客户', reason: '有实质讨论但规模未知', auto: true };
107	
108	  return { grade: 'B', label: '普通客户', reason: '信息不足默认B', auto: true };
109	}
110	
111	// ── 主循环 ──
112	const allResults = [];
113	for (let i = 0; i <= 4; i++) { if (s1.results[i]) allResults.push(...s1.results[i]); }
114	const candidates = allResults;
115	console.log('处理全部 ' + candidates.length + ' 个客户 (P0-P4)...\n');
116	
117	const enhanced = [];
118	for (const c of candidates) {
119	  const fid = c.cid ? c.cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
120	  const fp = path.join(chatDir, fid);
121	
122	  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
123	  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
124	  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
125	  let latestOurMsg = '', latestOurDate = '', latestCustMsg = '', latestCustDate = '';
126	  let lastCustomerMsgDays = 9999;
127	  let lastCustQuestion = '', lastCustQuestionDate = '', ourResponseQuality = 'N/A';
128	  let responseGapDays = -1, questionUnanswered = false;
129	
130	  if (fs.existsSync(fp)) {
131	    try {
132	      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
133	      const msgs = data.messages || [];
134	      msgCount = msgs.length;
135	
136	      for (const m of msgs) {
137	        const msg = m.message || m;
138	        const uid = msg.sender && msg.sender.uid || '';
139	        const text = getText(msg.content);
140	        const date = msg.createAt || '';
141	        if (isSys(msg.content)) { sysMsgs++; continue; }
142	
143	        if (uid === OUR_UID) {
144	          ourMsgs++; if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
145	        } else if (uid) {
146	          customerMsgs++;
147	          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
148	          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
149	        }
150	
151	        const lc = text.toLowerCase();
152	        if (/pi|proforma\s*invoice|invoice\s*sent|付款|deposit|定金|tt\s|wire\s*transfer|bank\s*transfer/.test(lc + text)) hasPI = true;
153	        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
154	        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
155	        if (/(price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
156	        if (/(sample|样品)/.test(lc)) hasSample = true;
157	        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
158	        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
159	        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
160	      }
161	
162	      // 找最后的客户提问
163	      const sortedMsgs = [...msgs].filter(m => !isSys((m.message || m).content)).sort((a, b) => ((b.message || b).createAt || 0) - ((a.message || a).createAt || 0));
164	      for (const m of sortedMsgs) {
165	        const msg = m.message || m;
166	        const uid = msg.sender && msg.sender.uid || '';
167	        const text = getText(msg.content);
168	        if (uid && uid !== OUR_UID && isQuestion(text)) { lastCustQuestion = text; lastCustQuestionDate = msg.createAt || ''; break; }
169	      }
170	
171	      if (lastCustQuestion && lastCustQuestionDate) {
172	        const qTs = new Date(lastCustQuestionDate).getTime();
173	        let respText = '', respDate = '';
174	        for (const m of [...sortedMsgs].reverse()) {
175	          const msg = m.message || m;
176	          const ts = (msg.createAt || 0);
177	          if ((msg.sender && msg.sender.uid) === OUR_UID && ts > qTs) { respText = getText(msg.content); respDate = msg.createAt || ''; break; }
178	        }
179	        if (respText) {
180	          const gapH = (new Date(respDate).getTime() - qTs) / 3600000;
181	          responseGapDays = Math.round(gapH / 24 * 10) / 10;
182	          const a = assessQuality(lastCustQuestion, respText);
183	          ourResponseQuality = a.q + ' (' + responseGapDays + 'd)';
184	        } else {
185	          ourResponseQuality = '未回复';
186	          responseGapDays = Math.round((NOW - qTs) / DAY * 10) / 10;
187	          questionUnanswered = true;
188	        }
189	      }
190	    } catch (e) { /* skip corrupt */ }
191	  }
192	
193	  const realMsgs = customerMsgs + ourMsgs;
194	  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;
195	  const country = c.country || '';
196	  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
197	  const isCore = coreMarkets.includes(country);
198	
199	  const obj = {
200	    name: c.name || '(未知)', country, isCore, daysAgo: c.daysAgo,
201	    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
202	    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
203	    latestOurMsg: latestOurMsg.substring(0, 100), latestCustMsg: latestCustMsg.substring(0, 100),
204	    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
205	    lastCustQuestion: lastCustQuestion.substring(0, 200), ourResponseQuality, responseGapDays, questionUnanswered,
206	    cid: c.cid, filename: fid,
207	  };
208	
209	  // 双轴分类
210	  const lc = determineLifecycle(obj);
211	  const ql = determineQuality(obj);
212	  const sil = silenceLabel(obj.lastCustomerMsgDays === '-' ? 999 : obj.lastCustomerMsgDays);
213	
214	  obj.stage = lc.stage;
215	  obj.stageLabel = lc.label;
216	  obj.stageIcon = lc.icon;
217	  obj.grade = ql.grade;
218	  obj.gradeLabel = ql.label;
219	  obj.gradeReason = ql.reason;
220	  obj.gradeAuto = ql.auto;
221	  obj.silenceState = sil;
222	
223	  // 行动信号
224	  const signals = [];
225	  if (questionUnanswered) signals.push('提问未回复');
226	  if (ourResponseQuality.startsWith('敷衍回复') && obj.daysAgo < 3) signals.push('敷衍回复需补救');
227	  if (responseGapDays > 3 && questionUnanswered) signals.push('超3天未回');
228	  if (ql.grade === 'S' || ql.grade === 'A') signals.push(ql.grade + '级客户');
229	  if (sil && obj.stage >= 1 && obj.stage <= 5) signals.push(sil);
230	  obj.actionSignals = signals;
231	
232	  enhanced.push(obj);
233	}
234	
235	// ── 按紧急度排序 ──
236	const urgencyOrder = { '待回复': 0, 'PI已发': 1, '谈判/样品': 2, '报价已发': 3, '初询沟通': 4, '订单执行中': 5, '已签收': 6, '售后': 7, '待分类': 8 };
237	enhanced.sort((a, b) => (urgencyOrder[a.stageLabel] || 9) - (urgencyOrder[b.stageLabel] || 9) || a.daysAgo - b.daysAgo);
238	
239	// ── 控制台输出 ──
240	const byStage = {};
241	for (const e of enhanced) {
242	  const k = e.stageLabel;
243	  if (!byStage[k]) byStage[k] = [];
244	  byStage[k].push(e);
245	}
246	for (const [stage, items] of Object.entries(byStage)) {
247	  console.log('── ' + (items[0].stageIcon || '') + ' ' + stage + ': ' + items.length + '人 ──');
248	  for (const e of items) {
249	    const flags = [];
250	    if (e.grade === 'S' || e.grade === 'A') flags.push(e.grade);
251	    if (e.isCore) flags.push('★');
252	    if (e.questionUnanswered) flags.push('⚠未回');
253	    const flagStr = flags.length > 0 ? ' [' + flags.join(' ') + ']' : '';
254	    console.log('  ' + String(e.daysAgo).padStart(2) + 'd | ' + (e.country || '??').padEnd(2) + ' | ' + (e.name || '(未知)').padEnd(28) + ' | ' + e.grade + '/' + e.stageLabel + flagStr);
255	    if (e.lastCustQuestion) {
256	      console.log('    ❓ ' + e.lastCustQuestion.substring(0, 80));
257	      console.log('    💬 ' + e.ourResponseQuality + (e.silenceState ? ' | ' + e.silenceState : ''));
258	    }
259	  }
260	  console.log('');
261	}
262	
263	// 统计
264	const gCount = { S: 0, A: 0, B: 0, C: 0, D: 0 };
265	const urgents = enhanced.filter(e => e.stageLabel === '待回复' || e.questionUnanswered);
266	for (const e of enhanced) gCount[e.grade] = (gCount[e.grade] || 0) + 1;
267	console.log('=== 双轴汇总 ===');
268	console.log('质量: S=' + gCount.S + ' A=' + gCount.A + ' B=' + gCount.B + ' C=' + gCount.C + ' D=' + gCount.D);
269	console.log('需立即行动: ' + urgents.length + '人 | 提问未回: ' + enhanced.filter(e => e.questionUnanswered).length + '人');
270	const pCounts = [0,1,2,3,4].map(i => (s1.results[i] || []).length);
271	console.log('总客户: ' + enhanced.length + ' (P0:' + pCounts[0] + ' P1:' + pCounts[1] + ' P2:' + pCounts[2] + ' P3:' + pCounts[3] + ' P4:' + pCounts[4] + ')\n');
272	
273	fs.writeFileSync(path.join(__dirname, '..', 'data', 's1_enhanced.json'), JSON.stringify(enhanced, null, 2));
274	console.log('已保存 data/s1_enhanced.json (' + enhanced.length + '条)');
275	
276	// ── HTML 看板 ──
277	generateDashboard(enhanced);
278	
279	function generateDashboard(data) {
280	  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
281	  const now = new Date();
282	  const today = now.toISOString().slice(0, 10);
283	  const timeStr = now.toLocaleString('zh-CN');
284	
285	  const byStage = {};
286	  for (const e of data) { const k = e.stageLabel || '待分类'; if (!byStage[k]) byStage[k] = []; byStage[k].push(e); }
287	
288	  // 静默分级
289	  const silenceTiers = [
290	    { label: '近期活跃 <3天', color: '#27ae60', maxD: 3 },
291	    { label: '近期活跃 3-7天', color: '#27ae60', maxD: 7, minD: 3 },
292	    { label: '短期静默 7-14天', color: '#3498db', maxD: 14, minD: 7 },
293	    { label: '中期静默 14-30天', color: '#f39c12', maxD: 30, minD: 14 },
294	    { label: '长期静默 30-90天', color: '#e67e22', maxD: 90, minD: 30 },
295	    { label: '沉淀 90天+', color: '#c0392b', maxD: 99999, minD: 90 },
296	  ];
297	  const silenceGroups = {};
298	  for (const tier of silenceTiers) silenceGroups[tier.label] = [];
299	  for (const e of data) {
300	    const d = e.lastCustomerMsgDays === '-' ? 9999 : e.lastCustomerMsgDays;
301	    for (const tier of silenceTiers) {
302	      if (d < tier.maxD && (tier.minD === undefined || d >= tier.minD)) {
303	        silenceGroups[tier.label].push(e);
304	        break;
305	      }
306	    }
307	  }
308	
309	  // KPI
310	  const total = data.length;
311	  const active3d = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays < 3).length;
312	  const silent90p = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays >= 90).length;
313	  const unread = data.filter(e => e.questionUnanswered).length;
314	  const changedCount = data.filter(e => e.daysAgo <= 3).length;
315	  const needsAction = data.filter(e => e.stageLabel === '待回复' || e.questionUnanswered || e.stageLabel === 'PI已发' || (e.stageLabel === '报价已发' && e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays <= 7)).length;
316	
317	  const kpiCards = [
318	    { num: total, label: '总客户', color: '#1a5276' },
319	    { num: active3d, label: '3天活跃', color: '#1a5276' },
320	    { num: silent90p, label: '超90天无互动', color: '#c0392b' },
321	    { num: unread, label: '未读消息', color: '#e67e22' },
322	    { num: changedCount, label: '本期变动', color: '#27ae60' },
323	    { num: needsAction, label: '需行动', color: '#8e44ad' },
324	  ];
325	
326	  // 双轴矩阵 (生命周期 × 质量)
327	  const stageOrder = ['待回复', '初询沟通', '报价已发', '谈判/样品', 'PI已发', '订单执行中', '已签收', '售后'];
328	  const gradeOrder = ['S', 'A', 'B', 'C', 'D'];
329	  const matrixData = {};
330	  for (const s of stageOrder) {
331	    matrixData[s] = {};
332	    for (const g of gradeOrder) matrixData[s][g] = [];
333	  }
334	  for (const e of data) {
335	    const s = e.stageLabel || '待分类';
336	    const g = e.grade || 'D';
337	    if (matrixData[s] && matrixData[s][g]) {
338	      matrixData[s][g].push(e);
339	    }
340	  }
341	
342	  const actions = {
343	    '待回复': { label: '待回复', byQuality: { S:'优先回复，搜索客户品牌/渠道背景后定制话术', A:'24h内回复，附工厂认证+大牌合作案例', B:'24h内回复，标准模板确认需求', C:'24h内回复，简要确认需求', D:'确认是否真实询盘后回复' }, defaultAction: '客户发来消息未回复，24小时内首次响应' },
