function determineQuality(e, fullCustText, fullConvText) {
  const ft = (fullConvText || '').toLowerCase();
  const ct = (fullCustText || '').toLowerCase();
  const latestText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();

  // ── 全量对话提取数量信息 ──
  const qtyMatches = ft.match(/(\d{3,})\s*(pcs|pieces|units|件|piece|pc)/gi) || [];
  let maxQty = 0;
  for (const qm of qtyMatches) {
    const n = parseInt(qm.match(/\d+/)[0], 10);
    if (n > maxQty) maxQty = n;
  }

  // ── 母婴品类信号（修正 D 误判用）──
  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|moses|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);

  // ── S 级信号（全量对话扫描）──
  const sSignals = [];
  if (/(brand|odm|oem|logo|label|custom.*(packag|design|logo|box)|hangtag|barcode|private.*label|own.*(brand|design|label|logo))/i.test(ft))
    sSignals.push('品牌/ODM/定制包装');
  if (/(amazon|walmart|shopify|retail.*(chain|store)|distributor.*network|wholesale.*channel|online.*store|ecommerce|e-commerce)/i.test(ft))
    sSignals.push('分销渠道');
  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
  if (/(website|company.*(name|profile)|business.*card|whatsapp.*business|linkedin|facebook.*page)/i.test(ft) ||
      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
    sSignals.push('公司资料/网站');
  if (/(again|another.*order|reorder|restock|more.*order|second.*order|new.*order|next.*order|repeat)/i.test(ft) ||
      /(last.*order|previous.*order|last.*(time|purchase)|before.*order)/i.test(ft))
    sSignals.push('复购信号');

  // ── A 级附加信号 ──
  const aSignals = [];
  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq))/i.test(ft))
    aSignals.push('MOQ已接受');
  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
    aSignals.push('样品已寄/在准备');
  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
    aSignals.push('深度沟通(' + e.realMsgs + '条)');
  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点)/i.test(ft))
    aSignals.push('价格谈判');
  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ft))
    aSignals.push('关心认证/验厂');
  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ft) && e.hasQuantity)
    aSignals.push('讨论运费+数量');
  if (/(colors?|sizes?|designs?|styles?|models?|patterns?|materials?|fabrics?)/i.test(ft) && e.realMsgs >= 8)
    aSignals.push('选款/选色讨论');

  // ── C 级降级信号 ──
  const cSignals = [];
  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use)/i.test(ft))
    cSignals.push('个人自用');
  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces))/i.test(ft))
    cSignals.push('小批量暗示');
  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample)
    cSignals.push('单次浅层互动');

  // ── D 级判定（修正版）──
  if (e.realMsgs <= 2 && e.customerMsgs === 0)
    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };

  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };

  // 非采购意图
  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };

  // ── 综合定级 ──
  const totalSSignals = sSignals.length;
  const totalASignals = aSignals.length;
  const totalCSignals = cSignals.length;

  // S: 2+ 个S级信号
  if (totalSSignals >= 2)
    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };

  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
  if (totalSSignals >= 1)
    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };

  if (totalASignals >= 2 && e.realMsgs >= 5)
    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };

  // C: 明确降级信号 + 无上升信号
  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };

  if (maxQty > 0 && maxQty <= 30 && totalSSignals === 0 && totalASignals === 0)
    return { grade: 'C', label: '低价值', reason: '明确小量≤30件', auto: true };

  // 单次互动无后续 → C（而非B）
  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample && !e.hasQuantity && e.lastCustomerMsgDays > 30)
    return { grade: 'C', label: '低价值', reason: '单次互动+30天无后续', auto: true };

  // B: 有实质互动，信号不足以升A/S也不足以降C/D
  if (e.realMsgs >= 3 && e.customerMsgs >= 1)
    return { grade: 'B', label: '普通客户', reason: '有互动但信号不足', auto: true };

  if (e.hasPrice || e.hasSample || e.hasQuantity)
    return { grade: 'B', label: '普通客户', reason: '有实质讨论', auto: true };

  return { grade: 'B', label: '普通客户', reason: '信息不足', auto: true };
}

