92	  }
93	
94	  // ── 母婴品类信号（修正 D 误判用）──
95	  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|moses|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);
96	
97	  // ── S 级信号（全量对话扫描）──
98	  const sSignals = [];
