100	    sSignals.push('品牌/ODM/定制包装');
101	  if (/(amazon|walmart|shopify|retail.*(chain|store)|distributor.*network|wholesale.*channel|online.*store|ecommerce|e-commerce)/i.test(ft))
102	    sSignals.push('分销渠道');
103	  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
104	  if (/(website|company.*(name|profile)|business.*card|whatsapp.*business|linkedin|facebook.*page)/i.test(ft) ||
105	      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
106	    sSignals.push('公司资料/网站');
107	  if (/(again|another.*order|reorder|restock|more.*order|second.*order|new.*order|next.*order|repeat)/i.test(ft) ||
108	      /(last.*order|previous.*order|last.*(time|purchase)|before.*order)/i.test(ft))
109	    sSignals.push('复购信号');
110	
111	  // ── A 级附加信号 ──
112	  const aSignals = [];
113	  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
114	  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq))/i.test(ft))
115	    aSignals.push('MOQ已接受');
116	  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
117	    aSignals.push('样品已寄/在准备');
118	  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
119	    aSignals.push('深度沟通(' + e.realMsgs + '条)');
120	  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点)/i.test(ft))
121	    aSignals.push('价格谈判');
122	  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ft))
123	    aSignals.push('关心认证/验厂');
124	  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ft) && e.hasQuantity)
125	    aSignals.push('讨论运费+数量');
126	  if (/(colors?|sizes?|designs?|styles?|models?|patterns?|materials?|fabrics?)/i.test(ft) && e.realMsgs >= 8)
127	    aSignals.push('选款/选色讨论');
128	
129	  // ── C 级降级信号 ──
130	  const cSignals = [];
131	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use)/i.test(ft))
132	    cSignals.push('个人自用');
133	  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces))/i.test(ft))
134	    cSignals.push('小批量暗示');
135	  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
136	  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample)
137	    cSignals.push('单次浅层互动');
138	
139	  // ── D 级判定（修正版）──
140	  if (e.realMsgs <= 2 && e.customerMsgs === 0)
141	    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
142	
143	  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
144	  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
145	    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };
146	
147	  // 非采购意图
148	  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
149	    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };
150	
151	  // ── 综合定级 ──
152	  const totalSSignals = sSignals.length;
153	  const totalASignals = aSignals.length;
154	  const totalCSignals = cSignals.length;
155	
156	  // S: 2+ 个S级信号
157	  if (totalSSignals >= 2)
158	    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
159	
160	  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
161	  if (totalSSignals >= 1)
162	    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };
163	
164	  if (totalASignals >= 2 && e.realMsgs >= 5)
165	    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };
166	
167	  // C: 明确降级信号 + 无上升信号
168	  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
169	    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };

