'  .kpi .num { font-size: 28px; font-weight: 700; }\n' +
'  .kpi .lbl { font-size: 11px; opacity: 0.9; }\n' +
'  .card { background: var(--bg-secondary); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }\n' +
'  .card-hd { background: var(--bg-tertiary); padding: 10px 14px; font-weight: 600; font-size: 13px; border-bottom: 1px solid var(--border); }\n' +
'  .card-hd span { font-weight: normal; font-size: 11px; color: var(--text-secondary); }\n' +
'  table.mx { width: 100%; border-collapse: collapse; font-size: 12px; }\n' +
'  table.mx th { padding: 6px 8px; border: 1px solid var(--border); background: var(--bg-tertiary); font-weight: 600; }\n' +
'  table.mx td { border: 1px solid var(--border); }\n' +
'  table.mx td.rl { text-align: left; font-weight: 600; padding: 6px 8px; }\n' +
