{"session_id":"088833bc-34b2-4149-96cf-18a5382504cb","transcript_path":"C:\Users\Administrator\.claude\projects\d--ClaudeWorkspace\088833bc-34b2-4149-96cf-18a5382504cb.jsonl","cwd":"d:\ClaudeWorkspace","permission_mode":"plan","effort":{"level":"xhigh"},"hook_event_name":"PostToolUse","tool_name":"Edit","tool_input":{"file_path":"d:\ClaudeWorkspace\08_客户跟进\Okki\scripts\enhanced_classify.js","old_string":"'  table.mx td.rl { text-align: center; font-weight: 600; padding: 6px 4px; width:52px; font-size:11px; }\n'","new_string":"'  table.mx td.rl { text-align: center; font-weight: 600; padding: 6px 4px; width:64px; font-size:11px; }\n'","replace_all":false},"tool_response":{"filePath":"d:\ClaudeWorkspace\08_客户跟进\Okki\scripts\enhanced_classify.js","oldString":"'  table.mx td.rl { text-align: center; font-weight: 600; padding: 6px 4px; width:52px; font-size:11px; }\n'","newString":"'  table.mx td.rl { text-align: center; font-weight: 600; padding: 6px 4px; width:64px; font-size:11px; }\n'","originalFile":"const fs = require('fs');
const path = require('path');

const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
const NOW = Date.now();
const DAY = 86400000;
const OUR_UID = '2500000853693@icbu';

// ── 工具函数 ──
const SYS_PATTERNS = [
  '自动接待将不再触发', 'Since you have read the conversation',
  'Marco大模型翻译', '阿里国际Marco大模型翻译',
  '买家有流失风险', 'Buyer has churn risk',
  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
  '反馈', 'AI给您生成了一条回复建议',
  'You have a visitor', 'This buyer has been pre-screened',
  '当前买家首次给您发消息', 'AI给您生成',
];
function isSys(c) { const t = c && c.text && c.text.content || ''; if (!t.trim()) return true; for (const p of SYS_PATTERNS) if (t.includes(p)) return true; return false; }
function getText(c) { return c && c.text && c.text.content || ''; }

const Q_PATTERNS = [/\?/, /(what|how|when|where|which|who|why|whom)/i, /(can you|could you|would you|will you|do you|is it|are you)/i, /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know))/i, /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i, /[吗呢吧啊]/, /[？]/, /(价格|报价|多少钱|什么价)/, /(样品|sample|打样)/i, /(MOQ|起订量|最小.*量)/i, /(交期|delivery.*time|lead.*time)/i];
function isQuestion(text) { if (!text || text.length < 3) return false; for (const p of Q_PATTERNS) if (p.test(text)) return true; return false; }

function assessQuality(qText, rText) {
  if (!rText || rText.trim().length === 0) return { q: '未回复', s: 0 };
  const len = rText.trim().length;
  if (/^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i.test(rText.trim()) || len < 15) return { q: '敷衍回复', s: 1 };
  if (len < 50) return { q: '简短回复', s: 2 };
  const qw = (qText || '').toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
  const rl = rText.toLowerCase();
  const m = qw.filter(w => rl.includes(w));
  return (m.length / Math.max(qw.length, 1) >= 0.3 || len >= 100) ? { q: '充分回复', s: 3 } : { q: '简短回复', s: 2 };
}

// ── 生命周期判定 ──
function determineLifecycle(e) {
  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();

  // 售后：质量问题/投诉
  if (/(problem|issue|damage|broken|wrong|defect|complain|refund|return|bad quality|poor quality|not good|有问题|坏的|退货|退款|投诉)/i.test(fullText)) return { stage: 8, label: '售后', icon: '🔧' };

  // 订单执行中：付款确认+生产/发货讨论
  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };

  // 已签收
  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };

  // PI已发（不限天数，只看信号）
  if (hasPI) return { stage: 5, label: 'PI已发', icon: '📄' };

  // 谈判/样品（不限天数）
  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10) return { stage: 4, label: '谈判/样品', icon: '🤝' };
  if (hasSample && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };

  // 报价已发（不限天数）
  if (hasPrice) return { stage: 3, label: '报价已发', icon: '💰' };

  // 待回复：客户有新消息未回
  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };

  // 初询沟通（不限天数）
  if (realMsgs >= 1) return { stage: 2, label: '初询沟通', icon: '📋' };

  return { stage: 0, label: '待分类', icon: '❓' };
}

// ── 沉默副状态 ──
function silenceLabel(days) {
  if (days >= 90) return '沉淀(90d+)';
  if (days >= 30) return '深度沉默(30-90d)';
  if (days >= 14) return '长期沉默(14-30d)';
  if (days >= 7) return '中期沉默(7-14d)';
  if (days >= 3) return '短期沉默(3-7d)';
  return '';
}

// ── 质量等级判定 ──
function determineQuality(e, fullCustText, fullConvText) {
  const ft = (fullConvText || '').toLowerCase();
  const ct = (fullCustText || '').toLowerCase();

  // ── 全量对话提取数量信息（从客户消息提取更可靠）──
  // 支持英/中/法/西/阿语常见数量单位
  const qtyMatches = ct.match(/(\d{3,})\s*(pcs|pieces|units?|unit[ée]s?|件|piece|pc|pce|paires?|douzaines?|qt[ée]|quantit[ée]s?|sets?|ensembles?)/gi) || [];
  let maxQty = 0;
  for (const qm of qtyMatches) {
    const n = parseInt(qm.match(/\d+/)[0], 10);
    if (n > maxQty) maxQty = n;
  }

  // ── 母婴品类信号（修正 D 误判用）──
  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);

  // ── S 级信号（严格版 — 优先用 ct 即客户消息）──
  const sSignals = [];
  // 品牌/ODM: 明确且有意图的组合（含法/西/阿语）
  if (/(odm|oem|private\s*(label|brand)|own\s*(brand|design|label)|custom\s*(logo|packaging|packing|design|label|box|bag|tag)|hangtag|barcode|brand\s*name|brand\s*label|your\s*logo|my\s*logo|our\s*logo|marque|personnalis[ée]|personnaliser|[ée]tiquette.*perso|logo.*perso|votre.*logo|mon.*logo|mon.*design|mon.*propre)/i.test(ct))
    sSignals.push('品牌/ODM');
  // 分销渠道: 明确平台或分销语言（含法/西/阿语）
  if (/(amazon|walmart|shopify|distributor|retail\s*(chain|store|shop)|wholesale\s*(channel|distributor|business)|sell\s*(on|through|in)\s*(amazon|walmart|shopify|online)|revendeur|distributeur|vendre.*(sur|en ligne|amazon)|boutique.*(en ligne|online)|tienda.*(online|en.linea)|mayorista)/i.test(ct))
    sSignals.push('分销渠道');
  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
  // 公司资料: 客户主动分享
  if (/(here.*(is|are).*(website|store|shop|link)|check.*(my|our).*(website|store|shop|page)|this\s*is\s*(my|our).*(website|store|shop)|find\s*(us|me).*(on|at).*(website|store))/i.test(ct) ||
      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
    sSignals.push('公司资料');
  // 复购: 明确的复购/追加语言
  if (/(reorder|restock|another\s*(order|shipment|batch|container)|second\s*(order|shipment)|repeat\s*order|buy\s*more|order\s*more|send\s*more|top\s*up)/i.test(ct))
    sSignals.push('复购信号');

  // ── A 级附加信号 ──
  const aSignals = [];
  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq)|(je|nous).*(prends?|commande|veux|voudrais).*500|500.*(va|marche|ok|d'accord)|pas.*probl[èe]me.*500)/i.test(ct))
    aSignals.push('MOQ已接受');
  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
    aSignals.push('样品已寄/在准备');
  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
    aSignals.push('深度沟通(' + e.realMsgs + '条)');
  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点|r[ée]duction|remise|rabais|n[ée]goci|trop.*(cher|[ée]lev[ée]|haut)|moins.*cher|prix.*(bas|moins)|descuento|rebaja|caro|muy.*caro|barato)/i.test(ct))
    aSignals.push('价格谈判');
  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ct))
    aSignals.push('关心认证/验厂');
  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ct) && e.hasQuantity)
    aSignals.push('讨论运费+数量');

  // ── C 级降级信号 ──
  const cSignals = [];
  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use|just.*for.*(me|myself|my.*kid|my.*baby)|pour moi|pour mon|personnel|usage.*personnel|uso.*personal|para mi)/i.test(ct))
    cSignals.push('个人自用');
  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces)|petit.*(quantit[ée]|commande)|peu.*(de|commande)|juste.*(quelques|un peu)|solo.*(pocos?|pocas?|unos?|unas?))/i.test(ct))
    cSignals.push('小批量暗示');
  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample && !e.hasQuantity)
    cSignals.push('单次浅层互动');

  // ── D 级判定（修正版）──
  if (e.realMsgs <= 2 && e.customerMsgs === 0)
    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };

  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };

  // 非采购意图
  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };

  // ── 综合定级 ──
  const totalSSignals = sSignals.length;
  const totalASignals = aSignals.length;
  const totalCSignals = cSignals.length;

  // S: 2+ 个S级信号
  if (totalSSignals >= 2)
    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };

  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
  if (totalSSignals >= 1)
    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };

  if (totalASignals >= 2 && e.realMsgs >= 5)
    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };

  // C: 明确降级信号 + 无上升信号
  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };

  if (maxQty > 0 && maxQty <= 30 && totalSSignals === 0 && totalASignals === 0)
    return { grade: 'C', label: '低价值', reason: '明确小量≤30件', auto: true };

  // 单次互动无后续 → C（而非B）
  if (e.realMsgs <= 4 && e.customerMsgs >= 1 && e.customerMsgs <= 2 && !e.hasPrice && !e.hasSample && !e.hasQuantity && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 30)
    return { grade: 'C', label: '低价值', reason: '单次互动+30天无后续', auto: true };

  // 浅互动+长期沉默 → C（"问完消失"模式）
  if (e.realMsgs <= 5 && e.customerMsgs <= 2 && totalSSignals === 0 && totalASignals <= 1 && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 60)
    return { grade: 'C', label: '低价值', reason: '浅互动+长期沉默(' + e.lastCustomerMsgDays + 'd)', auto: true };

  // B: 有实质互动，信号不足以升A/S也不足以降C/D
  if (e.realMsgs >= 3 && e.customerMsgs >= 1)
    return { grade: 'B', label: '普通客户', reason: '有互动但信号不足', auto: true };

  if (e.hasPrice || e.hasSample || e.hasQuantity)
    return { grade: 'B', label: '普通客户', reason: '有实质讨论', auto: true };

  return { grade: 'B', label: '普通客户', reason: '信息不足', auto: true };
}

// ── 主循环 ──
const allResults = [];
for (let i = 0; i <= 4; i++) { if (s1.results[i]) allResults.push(...s1.results[i]); }
const candidates = allResults;
console.log('处理全部 ' + candidates.length + ' 个客户 (P0-P4)...\n');

const enhanced = [];
for (const c of candidates) {
  const fid = c.cid ? c.cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
  const fp = path.join(chatDir, fid);

  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
  let latestOurMsg = '', latestOurDate = '', latestCustMsg = '', latestCustDate = '';
  let lastCustomerMsgDays = 9999;
  let lastCustQuestion = '', lastCustQuestionDate = '', ourResponseQuality = 'N/A';
  let responseGapDays = -1, questionUnanswered = false;
  let fullCustText = '', fullConvText = '';

  if (fs.existsSync(fp)) {
    try {
      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
      const msgs = data.messages || [];
      msgCount = msgs.length;

      for (const m of msgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const text = getText(msg.content);
        const date = msg.createAt || '';
        if (isSys(msg.content)) { sysMsgs++; continue; }

        if (uid === OUR_UID) {
          ourMsgs++; if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
          if (text.trim()) fullConvText += '[我方] ' + text + ' | ';
        } else if (uid) {
          customerMsgs++;
          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
          if (text.trim()) { fullCustText += text + ' | '; fullConvText += '[客户] ' + text + ' | '; }
          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
        }

        const lc = text.toLowerCase();
        if (/\bpi\b|proforma\s*invoice|invoice\s*sent|付款|deposit|定金|tt\s|wire\s*transfer|bank\s*transfer/.test(lc + text)) hasPI = true;
        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
        if (/(price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
        if (/(sample|样品)/.test(lc)) hasSample = true;
        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
      }

      // 找最后的客户提问
      const sortedMsgs = [...msgs].filter(m => !isSys((m.message || m).content)).sort((a, b) => ((b.message || b).createAt || 0) - ((a.message || a).createAt || 0));
      for (const m of sortedMsgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const text = getText(msg.content);
        if (uid && uid !== OUR_UID && isQuestion(text)) { lastCustQuestion = text; lastCustQuestionDate = msg.createAt || ''; break; }
      }

      if (lastCustQuestion && lastCustQuestionDate) {
        const qTs = new Date(lastCustQuestionDate).getTime();
        let respText = '', respDate = '';
        for (const m of [...sortedMsgs].reverse()) {
          const msg = m.message || m;
          const ts = (msg.createAt || 0);
          if ((msg.sender && msg.sender.uid) === OUR_UID && ts > qTs) { respText = getText(msg.content); respDate = msg.createAt || ''; break; }
        }
        if (respText) {
          const gapH = (new Date(respDate).getTime() - qTs) / 3600000;
          responseGapDays = Math.round(gapH / 24 * 10) / 10;
          const a = assessQuality(lastCustQuestion, respText);
          ourResponseQuality = a.q + ' (' + responseGapDays + 'd)';
        } else {
          ourResponseQuality = '未回复';
          responseGapDays = Math.round((NOW - qTs) / DAY * 10) / 10;
          questionUnanswered = true;
        }
      }
    } catch (e) { /* skip corrupt */ }
  }

  const realMsgs = customerMsgs + ourMsgs;
  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;
  const country = c.country || '';
  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
  const isCore = coreMarkets.includes(country);

  const obj = {
    name: c.name || '(未知)', country, isCore, daysAgo: c.daysAgo,
    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
    latestOurMsg: latestOurMsg.substring(0, 100), latestCustMsg: latestCustMsg.substring(0, 100),
    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
    lastCustQuestion: lastCustQuestion.substring(0, 200), ourResponseQuality, responseGapDays, questionUnanswered,
    cid: c.cid, filename: fid,
  };

  // 双轴分类
  const lc = determineLifecycle(obj);
  const ql = determineQuality(obj, fullCustText, fullConvText);
  const sil = silenceLabel(obj.lastCustomerMsgDays === '-' ? 999 : obj.lastCustomerMsgDays);

  obj.stage = lc.stage;
  obj.stageLabel = lc.label;
  obj.stageIcon = lc.icon;
  obj.grade = ql.grade;
  obj.gradeLabel = ql.label;
  obj.gradeReason = ql.reason;
  obj.gradeAuto = ql.auto;
  obj.silenceState = sil;

  // 行动信号
  const signals = [];
  if (questionUnanswered) signals.push('提问未回复');
  if (ourResponseQuality.startsWith('敷衍回复') && obj.daysAgo < 3) signals.push('敷衍回复需补救');
  if (responseGapDays > 3 && questionUnanswered) signals.push('超3天未回');
  if (ql.grade === 'S' || ql.grade === 'A') signals.push(ql.grade + '级客户');
  if (sil && obj.stage >= 1 && obj.stage <= 5) signals.push(sil);
  obj.actionSignals = signals;

  enhanced.push(obj);
}

// ── 按紧急度排序 ──
const urgencyOrder = { '待回复': 0, 'PI已发': 1, '谈判/样品': 2, '报价已发': 3, '初询沟通': 4, '订单执行中': 5, '已签收': 6, '售后': 7, '待分类': 8 };
enhanced.sort((a, b) => (urgencyOrder[a.stageLabel] || 9) - (urgencyOrder[b.stageLabel] || 9) || a.daysAgo - b.daysAgo);

// ── 控制台输出 ──
const byStage = {};
for (const e of enhanced) {
  const k = e.stageLabel;
  if (!byStage[k]) byStage[k] = [];
  byStage[k].push(e);
}
for (const [stage, items] of Object.entries(byStage)) {
  console.log('── ' + (items[0].stageIcon || '') + ' ' + stage + ': ' + items.length + '人 ──');
  for (const e of items) {
    const flags = [];
    if (e.grade === 'S' || e.grade === 'A') flags.push(e.grade);
    if (e.isCore) flags.push('★');
    if (e.questionUnanswered) flags.push('⚠未回');
    const flagStr = flags.length > 0 ? ' [' + flags.join(' ') + ']' : '';
    console.log('  ' + String(e.daysAgo).padStart(2) + 'd | ' + (e.country || '??').padEnd(2) + ' | ' + (e.name || '(未知)').padEnd(28) + ' | ' + e.grade + '/' + e.stageLabel + flagStr);
    if (e.lastCustQuestion) {
      console.log('    ❓ ' + e.lastCustQuestion.substring(0, 80));
      console.log('    💬 ' + e.ourResponseQuality + (e.silenceState ? ' | ' + e.silenceState : ''));
    }
  }
  console.log('');
}

// 统计
const gCount = { S: 0, A: 0, B: 0, C: 0, D: 0 };
const urgents = enhanced.filter(e => e.stageLabel === '待回复' || e.questionUnanswered);
for (const e of enhanced) gCount[e.grade] = (gCount[e.grade] || 0) + 1;
console.log('=== 双轴汇总 ===');
console.log('质量: S=' + gCount.S + ' A=' + gCount.A + ' B=' + gCount.B + ' C=' + gCount.C + ' D=' + gCount.D);
console.log('需立即行动: ' + urgents.length + '人 | 提问未回: ' + enhanced.filter(e => e.questionUnanswered).length + '人');
const pCounts = [0,1,2,3,4].map(i => (s1.results[i] || []).length);
console.log('总客户: ' + enhanced.length + ' (P0:' + pCounts[0] + ' P1:' + pCounts[1] + ' P2:' + pCounts[2] + ' P3:' + pCounts[3] + ' P4:' + pCounts[4] + ')\n');

fs.writeFileSync(path.join(__dirname, '..', 'data', 's1_enhanced.json'), JSON.stringify(enhanced, null, 2));
console.log('已保存 data/s1_enhanced.json (' + enhanced.length + '条)');

// ── HTML 看板 ──
generateDashboard(enhanced);

function generateDashboard(data) {
  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  const now = new Date();
  const today = now.toISOString().slice(0, 10);
  const timeStr = now.toLocaleString('zh-CN');

  const byStage = {};
  for (const e of data) { const k = e.stageLabel || '待分类'; if (!byStage[k]) byStage[k] = []; byStage[k].push(e); }

  // 静默分级
  const silenceTiers = [
    { label: '近期活跃 <3天', color: '#27ae60', maxD: 3 },
    { label: '近期活跃 3-7天', color: '#27ae60', maxD: 7, minD: 3 },
    { label: '短期静默 7-14天', color: '#3498db', maxD: 14, minD: 7 },
    { label: '中期静默 14-30天', color: '#f39c12', maxD: 30, minD: 14 },
    { label: '长期静默 30-90天', color: '#e67e22', maxD: 90, minD: 30 },
    { label: '沉淀 90天+', color: '#c0392b', maxD: 99999, minD: 90 },
  ];
  const silenceGroups = {};
  for (const tier of silenceTiers) silenceGroups[tier.label] = [];
  for (const e of data) {
    const d = e.lastCustomerMsgDays === '-' ? 9999 : e.lastCustomerMsgDays;
    for (const tier of silenceTiers) {
      if (d < tier.maxD && (tier.minD === undefined || d >= tier.minD)) {
        silenceGroups[tier.label].push(e);
        break;
      }
    }
  }

  // KPI
  const total = data.length;
  const active3d = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays < 3).length;
  const silent90p = data.filter(e => e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays >= 90).length;
  const unread = data.filter(e => e.questionUnanswered).length;
  const changedCount = data.filter(e => e.daysAgo <= 3).length;
  const needsAction = data.filter(e => e.stageLabel === '待回复' || e.questionUnanswered || e.stageLabel === 'PI已发' || (e.stageLabel === '报价已发' && e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays <= 7)).length;

  const kpiCards = [
    { num: total, label: '总客户', color: '#1a5276' },
    { num: active3d, label: '3天活跃', color: '#1a5276' },
    { num: silent90p, label: '超90天无互动', color: '#c0392b' },
    { num: unread, label: '未读消息', color: '#e67e22' },
    { num: changedCount, label: '本期变动', color: '#27ae60' },
    { num: needsAction, label: '需行动', color: '#8e44ad' },
  ];

  // 双轴矩阵 (生命周期 × 质量)
  const stageOrder = ['待回复', '初询沟通', '报价已发', '谈判/样品', 'PI已发', '订单执行中', '已签收', '售后'];
  const gradeOrder = ['S', 'A', 'B', 'C', 'D'];
  const matrixData = {};
  for (const s of stageOrder) {
    matrixData[s] = {};
    for (const g of gradeOrder) matrixData[s][g] = [];
  }
  for (const e of data) {
    const s = e.stageLabel || '待分类';
    const g = e.grade || 'D';
    if (matrixData[s] && matrixData[s][g]) {
      matrixData[s][g].push(e);
    }
  }

  const actions = {
    '待回复': { label: '待回复', byQuality: { S:'优先回复，搜索客户品牌/渠道背景后定制话术', A:'24h内回复，附工厂认证+大牌合作案例', B:'24h内回复，标准模板确认需求', C:'24h内回复，简要确认需求', D:'确认是否真实询盘后回复' }, defaultAction: '客户发来消息未回复，24小时内首次响应' },
    '初询沟通': { label: '初询沟通', byQuality: { S:'研究客户品牌/店铺/渠道，定制话术，建立"同级别工厂伙伴"认知', A:'发送精选目录+工厂认证+BSCI/ISO证书，推进需求确认', B:'标准目录发送，确认MOQ和产品需求', C:'简要回复，对方表达需求后再深挖', D:'确认是否真实询盘，标准模板回复' }, defaultAction: '了解客户需求，发送目录/工厂资料' },
    '报价已发': { label: '报价已发', byQuality: { S:'48h跟进，每次带新信息/价值（新品/案例/市场数据）', A:'48h跟进，附相关产品推荐或同行案例', B:'3-5天温和提醒，确认是否收到报价', C:'3-5天提醒一次，3轮无回应转入沉默管理', D:'5-7天一次，标准提醒' }, defaultAction: '跟进报价反馈，解答疑问' },
    '谈判/样品': { label: '谈判/样品', byQuality: { S:'主动做mockup/方案，不等客户开口，48h跟进', A:'关注样品反馈/价格谈判进展，48h确认状态', B:'确认是否需调整报价或规格，48-72h跟进', C:'对方确认意向后才做额外方案', D:'跟进但不投入过多定制资源' }, defaultAction: '推动决策，解决疑虑' },
    'PI已发': { label: 'PI已发', byQuality: { S:'PI发出48h确认收到，第5天提醒付款，第7天催款', A:'PI发出48h确认收到，第5天提醒，PI到期前提醒', B:'48h确认收到，PI有效期结束前提醒', C:'确认收到，到期前提醒一次', D:'确认收到即可' }, defaultAction: '确认PI收到，跟进付款' },
    '订单执行中': { label: '订单执行中', byQuality: { S:'每周主动同步进度，拍照/视频，关键节点提前通知', A:'每周同步，关键节点通知', B:'关键节点通知（排产/发货）', C:'发货时通知', D:'发货时通知' }, defaultAction: '关键节点主动通知（排产/完成/发货）' },
    '已签收': { label: '已签收', byQuality: { S:'签收7天回访，同步新品+定制方案，争取复购', A:'签收7天回访，发新品目录', B:'签收7天回访，确认满意度', C:'签收后回访一次', D:'签收后回访一次' }, defaultAction: '确认收货满意，推动复购' },
    '售后': { label: '售后', byQuality: { S:'≤1h响应，主动提供补偿方案', A:'≤1h响应，24h内给方案', B:'24h响应', C:'24h内回复', D:'24h内回复' }, defaultAction: '快速响应，妥善处理' },
  };

  // 构建静默HTML
  const silenceHtml = silenceTiers.map(tier => {
    const items = silenceGroups[tier.label] || [];
    if (items.length === 0) return '';
    const itemsHtml = items.sort((a, b) => {
      const da = a.lastCustomerMsgDays === '-' ? 9999 : a.lastCustomerMsgDays;
      const db = b.lastCustomerMsgDays === '-' ? 9999 : b.lastCustomerMsgDays;
      return db - da;
    }).map(e => {
      const d = e.lastCustomerMsgDays === '-' ? '?' : e.lastCustomerMsgDays;
      return '<div style="display:flex;justify-content:space-between;padding:2px 0;font-size:11px;"><span>' + esc(e.name) + ' <span style="color:var(--text-secondary);">' + esc(e.country || '??') + '</span></span><span>' + d + '天</span></div>';
    }).join('');
    return '<div>' +
      '<div onclick="var d=this.nextElementSibling;d.style.display=d.style.display===\'block\'?\'none\':\'block\'" style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid var(--border);cursor:pointer;">' +
      '<span>● <strong style="color:' + tier.color + ';">' + tier.label + '</strong></span>' +
      '<strong style="font-size:16px;color:' + tier.color + ';">' + items.length + '</strong></div>' +
      '<div style="display:none;padding:8px 14px;background:rgba(' + (tier.color === '#27ae60' ? '39,174,96' : tier.color === '#3498db' ? '52,152,219' : tier.color === '#f39c12' ? '243,156,18' : tier.color === '#e67e22' ? '230,126,34' : '192,57,43') + ',0.08);border-bottom:1px solid var(--border);">' + itemsHtml + '</div></div>';
  }).filter(Boolean).join('');

  // 市场分布
  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
  const coreNames = { SD:'苏丹', EG:'埃及', CD:'刚果民主', ZM:'赞比亚', CI:'科特迪瓦', SA:'沙特', AE:'阿联酋' };
  const marketData = {};
  for (const mk of coreMarkets) marketData[mk] = { count: 0, sa: 0, action: 0 };
  for (const e of data) {
    const c = e.country || '';
    if (marketData[c] !== undefined) {
      marketData[c].count++;
      if (e.grade === 'S' || e.grade === 'A') marketData[c].sa++;
      if (e.stageLabel === '待回复' || e.questionUnanswered || e.stageLabel === 'PI已发') marketData[c].action++;
    }
  }
  const marketRows = coreMarkets.filter(mk => marketData[mk].count > 0).map(mk => {
    const md = marketData[mk];
    return '<tr><td style="padding:8px;border:1px solid var(--border);font-weight:600;">' + coreNames[mk] + '</td>' +
      '<td style="text-align:center;padding:8px;border:1px solid var(--border);">' + md.count + '</td>' +
      '<td style="text-align:center;padding:8px;border:1px solid var(--border);">' + md.sa + '</td>' +
      '<td style="text-align:center;padding:8px;border:1px solid var(--border);color:#c0392b;font-weight:bold;">' + md.action + '</td></tr>';
  }).join('');

  // 矩阵表格行
  const matrixRows = stageOrder.map(s => {
    const cells = gradeOrder.map(g => {
      const items = matrixData[s] ? (matrixData[s][g] || []) : [];
      const n = items.length;
      if (n === 0) return '<td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td>';
      let opacity = Math.min(0.5, 0.15 + n * 0.005);
      if (g === 'S') opacity = Math.min(0.5, 0.2 + n * 0.02);
