'document.addEventListener("keydown", function(e) { if (e.key === "Escape") closeModal(); });\n' +
'</script>\n</body>\n</html>';

  const outPath = path.join(__dirname, '..', 'output', 'dashboard_' + today + '.html');
  fs.writeFileSync(outPath, html, 'utf-8');
  console.log('看板 → ' + outPath);

  // 同时保存增强后的全量JSON
  fs.writeFileSync(path.join(__dirname, '..', 'data', 's1_enhanced_full.json'), JSON.stringify(data, null, 2));
