const fs = require('fs');
const path = require('path');

const mainFile = path.join(__dirname, 'enhanced_classify.js');
const sectionFile = path.join(__dirname, 'modal_section.txt');

let f = fs.readFileSync(mainFile, 'utf8');
const newSection = fs.readFileSync(sectionFile, 'utf8').trimEnd();

const start = f.indexOf("'function gradeTag(g) {");
const end = f.indexOf("'</script>\\n</body>\\n</html>'");

if (start < 0 || end < 0) {
  console.log('Error: cannot find markers. start=' + start + ' end=' + end);
  process.exit(1);
}

f = f.substring(0, start) + newSection + '\n' + f.substring(end);
fs.writeFileSync(mainFile, f, 'utf8');
console.log('OK.');

